// frontend/src/pages/JS JobMatcher.js
import React, { useState, useEffect } from 'react';
import axios from 'axios';

const JobMatcher = () => {
  const [jobDescription, setJobDescription] = useState('');
  const [resumeText, setResumeText] = useState('');
  const [matchResult, setMatchResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [aiStatus, setAiStatus] = useState('checking');
  const [resumeCategory, setResumeCategory] = useState(null);

  const token = localStorage.getItem('token');
  const BACKEND_URL = 'http://localhost:5000';
  const AI_API_URL = 'http://localhost:5001';

  // Check AI Service Status and Load Resume
  useEffect(() => {
    checkAIStatus();
    loadUserResume();
  }, []);

  const checkAIStatus = async () => {
    try {
      const response = await axios.get(`${AI_API_URL}/health`);
      setAiStatus(response.data.status === 'AI Service Running' ? 'online' : 'offline');
    } catch (error) {
      setAiStatus('offline');
    }
  };

  const loadUserResume = async () => {
    try {
      let resumeTextFromStorage = '';
      
      // First try to get from backend
      try {
        const response = await axios.get(`${BACKEND_URL}/api/applications`, {
          headers: { 'x-auth-token': token }
        });
        if (response.data && response.data.length > 0) {
          // Find the resume upload entry
          const resumeEntry = response.data.find(app => app.jobTitle === 'Resume Upload');
          if (resumeEntry && resumeEntry.resumeText) {
            resumeTextFromStorage = resumeEntry.resumeText;
          }
          // If not found, use the first application's resume text
          if (!resumeTextFromStorage && response.data[0].resumeText) {
            resumeTextFromStorage = response.data[0].resumeText;
          }
        }
      } catch (err) {
        console.log('Backend fetch failed, checking localStorage');
      }
      
      // Fallback to localStorage
      if (!resumeTextFromStorage) {
        resumeTextFromStorage = localStorage.getItem('userResume') || '';
        if (resumeTextFromStorage) {
          console.log('Resume loaded from localStorage');
        }
      }
      
      setResumeText(resumeTextFromStorage);
      
      if (resumeTextFromStorage) {
        predictResumeCategory(resumeTextFromStorage);
      } else {
        console.log('No resume found');
      }
    } catch (error) {
      console.error('Error loading resume:', error);
    }
  };

  const predictResumeCategory = async (text) => {
    try {
      const response = await axios.post(`${AI_API_URL}/predict/category`, {
        resume_text: text
      });
      setResumeCategory(response.data.predicted_category);
    } catch (error) {
      console.error('Category prediction failed:', error);
    }
  };

  const analyzeMatch = async () => {
    if (!jobDescription) {
      alert('Please paste a job description');
      return;
    }

    if (!resumeText) {
      alert('No resume found! Please upload your resume first in Upload Resume page.');
      return;
    }

    setLoading(true);
    try {
      const response = await axios.post(`${AI_API_URL}/predict/match`, {
        resume_text: resumeText,
        job_description: jobDescription,
        job_title: 'Job Position'
      });
      setMatchResult(response.data);
    } catch (error) {
      console.error('Match analysis failed:', error);
      alert('AI Service error. Make sure Python API is running on port 5001');
    }
    setLoading(false);
  };

  const getMatchColor = (score) => {
    if (score >= 70) return '#28a745';
    if (score >= 50) return '#17a2b8';
    if (score >= 30) return '#ffc107';
    return '#dc3545';
  };

  const getMatchText = (score) => {
    if (score >= 70) return 'Excellent Match! 🎯';
    if (score >= 50) return 'Good Match 👍';
    if (score >= 30) return 'Fair Match 📝';
    return 'Poor Match ❌';
  };

  return (
    <div style={{ padding: '20px', maxWidth: '1400px', margin: '0 auto' }}>
      <h1 style={{ color: '#333', marginBottom: '20px' }}>🎯 Job Match Analyzer</h1>

      {/* AI Status Indicator */}
      <div style={{
        padding: '10px',
        borderRadius: '5px',
        marginBottom: '20px',
        background: aiStatus === 'online' ? '#d4edda' : '#f8d7da',
        color: aiStatus === 'online' ? '#155724' : '#721c24'
      }}>
        {aiStatus === 'online' ? '✅ AI Service Connected' : '⚠️ AI Service Offline - Run python predict_api.py'}
      </div>

      {/* Resume Category Display */}
      {resumeCategory && (
        <div style={{
          background: '#e8f4f8',
          padding: '15px',
          borderRadius: '10px',
          marginBottom: '20px'
        }}>
          <strong>📄 Your Resume Category:</strong> 
          <span style={{
            background: '#007bff',
            color: 'white',
            padding: '5px 15px',
            borderRadius: '20px',
            marginLeft: '10px',
            display: 'inline-block'
          }}>
            {resumeCategory}
          </span>
          <p style={{ color: '#6c757d', fontSize: '12px', marginTop: '5px' }}>
            AI predicts you're best suited for {resumeCategory} roles
          </p>
        </div>
      )}

      {/* Resume Status Warning */}
      {!resumeText && (
        <div style={{
          padding: '10px',
          borderRadius: '5px',
          marginBottom: '20px',
          background: '#fff3cd',
          color: '#856404'
        }}>
          ⚠️ No resume found. Please go to <strong>Upload Resume</strong> page and save your resume first.
        </div>
      )}

      <div style={{
        display: 'grid',
        gridTemplateColumns: '1fr 1fr',
        gap: '30px'
      }}>
        {/* Left Column - Input */}
        <div>
          <div style={{ marginBottom: '15px' }}>
            <label style={{ display: 'block', marginBottom: '10px', fontWeight: 'bold' }}>📝 Job Description</label>
            <textarea
              rows="15"
              value={jobDescription}
              onChange={(e) => setJobDescription(e.target.value)}
              placeholder="Paste the job description here...
              
Example:
Looking for a Python Developer with 3+ years experience in Django, React, and SQL. Must have strong communication skills and experience with AWS."
              style={{
                width: '100%',
                padding: '10px',
                border: '1px solid #ddd',
                borderRadius: '5px',
                fontFamily: 'monospace',
                fontSize: '14px',
                minHeight: '300px'
              }}
            />
          </div>

          <button 
            onClick={analyzeMatch}
            disabled={loading || aiStatus === 'offline' || !resumeText}
            style={{
              background: (!resumeText || loading || aiStatus === 'offline') ? '#6c757d' : '#007bff',
              color: 'white',
              border: 'none',
              padding: '12px 30px',
              borderRadius: '5px',
              cursor: (!resumeText || loading || aiStatus === 'offline') ? 'not-allowed' : 'pointer',
              fontSize: '16px',
              marginTop: '15px'
            }}
          >
            {loading ? '🤖 Analyzing...' : '🔍 Analyze Match'}
          </button>
        </div>

        {/* Right Column - Results */}
        <div>
          <h3>📊 Match Results</h3>
          
          {matchResult ? (
            <div style={{
              background: 'white',
              border: '1px solid #ddd',
              borderRadius: '10px',
              padding: '20px',
              textAlign: 'center'
            }}>
              <div style={{
                width: '150px',
                height: '150px',
                borderRadius: '50%',
                border: `8px solid ${getMatchColor(matchResult.match_score)}`,
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                justifyContent: 'center',
                margin: '0 auto 20px'
              }}>
                <span style={{ fontSize: '48px', fontWeight: 'bold' }}>{matchResult.match_score}%</span>
                <span style={{ fontSize: '14px' }}>Match</span>
              </div>

              <div style={{ fontSize: '24px', fontWeight: 'bold', marginBottom: '20px', color: getMatchColor(matchResult.match_score) }}>
                {getMatchText(matchResult.match_score)}
              </div>

              <div style={{ textAlign: 'left', marginBottom: '15px' }}>
                <div style={{ fontWeight: 'bold', marginBottom: '8px' }}>🎯 Matching Skills:</div>
                <div>{matchResult.matching_skills} / {matchResult.total_job_skills}</div>
              </div>

              <div style={{ textAlign: 'left', marginBottom: '15px' }}>
                <div style={{ fontWeight: 'bold', marginBottom: '8px' }}>📋 Your Top Skills:</div>
                <div style={{ display: 'flex', flexWrap: 'wrap', gap: '8px' }}>
                  {(matchResult.resume_skills || []).map((skill, i) => (
                    <span key={i} style={{ padding: '5px 12px', borderRadius: '20px', fontSize: '12px', background: '#d4edda', color: '#155724' }}>
                      {skill}
                    </span>
                  ))}
                  {(!matchResult.resume_skills || matchResult.resume_skills.length === 0) && (
                    <span style={{ color: '#6c757d', fontSize: '12px' }}>No skills detected</span>
                  )}
                </div>
              </div>

              <div style={{ textAlign: 'left', marginBottom: '15px' }}>
                <div style={{ fontWeight: 'bold', marginBottom: '8px' }}>💼 Job Required Skills:</div>
                <div style={{ display: 'flex', flexWrap: 'wrap', gap: '8px' }}>
                  {(matchResult.job_skills || []).map((skill, i) => (
                    <span key={i} style={{ padding: '5px 12px', borderRadius: '20px', fontSize: '12px', background: '#fff3cd', color: '#856404' }}>
                      {skill}
                    </span>
                  ))}
                  {(!matchResult.job_skills || matchResult.job_skills.length === 0) && (
                    <span style={{ color: '#6c757d', fontSize: '12px' }}>No specific skills detected</span>
                  )}
                </div>
              </div>

              <div style={{ marginTop: '15px', padding: '10px', background: '#f8f9fa', borderRadius: '5px' }}>
                {matchResult.match_score >= 70 && (
                  <p>✅ You're a great fit! Prepare for an interview.</p>
                )}
                {matchResult.match_score >= 50 && matchResult.match_score < 70 && (
                  <p>📈 Good match! Highlight your matching skills in your application.</p>
                )}
                {matchResult.match_score >= 30 && matchResult.match_score < 50 && (
                  <p>📚 Fair match. Consider upskilling in missing areas.</p>
                )}
                {matchResult.match_score < 30 && (
                  <p>🔄 Low match. Look for roles that better align with your skills.</p>
                )}
              </div>
            </div>
          ) : (
            <div style={{
              textAlign: 'center',
              padding: '50px',
              background: '#f8f9fa',
              borderRadius: '10px'
            }}>
              <p>📌 Paste a job description and click "Analyze Match"</p>
              <p style={{ color: '#6c757d', fontSize: '12px' }}>
                AI will compare your resume with the job and show match score
              </p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default JobMatcher;
